def notify_deployment(deployment_info):
    status_emoji = "✅" if deployment_info['success'] else "❌"
    status_text = "Successful" if deployment_info['success'] else "Failed"

    message = f"""
    {status_emoji} Deployment {status_text}

    Project: {deployment_info['project']}
    Branch: {deployment_info['branch']}
    Version: {deployment_info['version']}
    Environment: {deployment_info['environment']}
    Duration: {deployment_info['duration']}s
    """

    if not deployment_info['success']:
        message += f"\nError: {deployment_info['error']}"

    send_email(
        to="#deployments",
        subject=f"{status_emoji} Deploy {deployment_info['project']} {deployment_info['version']}",
        body=message,
        service="slack"
    )

