import time
from collections import defaultdict

class EmailRateLimiter:
    def __init__(self, max_per_minute=50):
        self.max_per_minute = max_per_minute
        self.sent_times = defaultdict(list)

    def can_send(self, service_name):
        now = time.time()
        # Remove timestamps older than 1 minute
        self.sent_times[service_name] = [
            t for t in self.sent_times[service_name]
            if now - t < 60
        ]
        return len(self.sent_times[service_name]) < self.max_per_minute

    def record_send(self, service_name):
        self.sent_times[service_name].append(time.time())

limiter = EmailRateLimiter()

def send_with_rate_limit(to, subject, body, service):
    if limiter.can_send(service):
        result = send_email(to=to, subject=subject, body=body, service=service)
        if result['success']:
            limiter.record_send(service)
        return result
    else:
        return {
            'success': False,
            'error': 'Rate limit exceeded. Try again later.',
            'message': f'Rate limit exceeded for {service}'
        }

