import asyncio

async def send_with_retry(to, subject, body, service, max_retries=3):
    services_to_try = [service, 'sendgrid', 'mailgun', 'smtp']

    for attempt in range(max_retries):
        for svc in services_to_try:
            try:
                result = send_email(
                    to=to,
                    subject=subject,
                    body=body,
                    service=svc
                )
                if result['success']:
                    return result
            except Exception as e:
                print(f"Attempt {attempt + 1} with {svc} failed: {e}")
                continue

        if attempt < max_retries - 1:
            wait_time = 2 ** attempt  # Exponential backoff
            print(f"All services failed, retrying in {wait_time}s...")
            await asyncio.sleep(wait_time)

    return {
        'success': False,
        'error': f'Failed to send after {max_retries} attempts',
        'message': f'Could not deliver email to {to}'
    }

# Usage
